import pytest
from unittest.mock import Mock

class TestCopyFunction:
    @pytest.fixture
    def prepared_request(self):
        request = Mock()
        request.method = 'GET'
        request.url = 'http://example.com'
        request.headers = {'Content-Type': 'application/json'}
        request._cookies = Mock()
        request.body = 'test body'
        request.hooks = {}
        request._body_position = 0
        return request

    def test_copy_normal_case(self, prepared_request):
        copied_request = prepared_request.copy()
        assert copied_request.method == prepared_request.method
        assert copied_request.url == prepared_request.url
        assert copied_request.headers == prepared_request.headers
        assert copied_request._cookies == prepared_request._cookies
        assert copied_request.body == prepared_request.body
        assert copied_request.hooks == prepared_request.hooks
        assert copied_request._body_position == prepared_request._body_position

    def test_copy_with_none_headers(self, prepared_request):
        prepared_request.headers = None
        copied_request = prepared_request.copy()
        assert copied_request.headers is None

    def test_copy_with_empty_headers(self, prepared_request):
        prepared_request.headers = {}
        copied_request = prepared_request.copy()
        assert copied_request.headers == {}

    def test_copy_with_empty_body(self, prepared_request):
        prepared_request.body = ''
        copied_request = prepared_request.copy()
        assert copied_request.body == ''

    def test_copy_with_none_body(self, prepared_request):
        prepared_request.body = None
        copied_request = prepared_request.copy()
        assert copied_request.body is None

    def test_copy_with_cookies(self, prepared_request):
        prepared_request._cookies = Mock()
        copied_request = prepared_request.copy()
        assert copied_request._cookies == prepared_request._cookies

    def test_copy_with_hooks(self, prepared_request):
        prepared_request.hooks = {'response': Mock()}
        copied_request = prepared_request.copy()
        assert copied_request.hooks == prepared_request.hooks

    def test_copy_with_body_position(self, prepared_request):
        prepared_request._body_position = 5
        copied_request = prepared_request.copy()
        assert copied_request._body_position == prepared_request._body_position

    def test_copy_method(self, prepared_request):
        prepared_request.method = 'POST'
        copied_request = prepared_request.copy()
        assert copied_request.method == 'POST'

    def test_copy_url(self, prepared_request):
        prepared_request.url = 'http://test.com'
        copied_request = prepared_request.copy()
        assert copied_request.url == 'http://test.com'

    def test_copy_invalid_method(self, prepared_request):
        prepared_request.method = 'INVALID_METHOD'
        copied_request = prepared_request.copy()
        assert copied_request.method == 'INVALID_METHOD'

