import cookielib
from unittest.mock import MagicMock

# Assuming the function is part of a class named `PreparedRequest`
class TestPreparedRequest:
    @pytest.fixture
    def prepared_request(self):
        return PreparedRequest()

    def test_prepare_cookies_with_cookiejar(self, prepared_request):
        cookie_jar = cookielib.CookieJar()
        prepared_request.prepare_cookies(cookie_jar)
        assert prepared_request._cookies == cookie_jar

    def test_prepare_cookies_with_dict(self, prepared_request):
        cookies_dict = {'session_id': 'abc123', 'user_id': 'user42'}
        prepared_request.prepare_cookies(cookies_dict)
        assert isinstance(prepared_request._cookies, cookielib.CookieJar)

    def test_prepare_cookies_sets_cookie_header(self, prepared_request, monkeypatch):
        cookies_dict = {'session_id': 'abc123'}
        monkeypatch.setattr(prepared_request, 'headers', {})

        def mock_get_cookie_header(cookies, request):
            return 'session_id=abc123'

        monkeypatch.setattr('get_cookie_header', mock_get_cookie_header)

        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == 'session_id=abc123'

    def test_prepare_cookies_no_effect_after_first_call(self, prepared_request, monkeypatch):
        cookies_dict = {'session_id': 'abc123'}
        monkeypatch.setattr(prepared_request, 'headers', {})

        def mock_get_cookie_header(cookies, request):
            return 'session_id=abc123'

        monkeypatch.setattr('get_cookie_header', mock_get_cookie_header)

        prepared_request.prepare_cookies(cookies_dict)
        prepared_request.prepare_cookies(cookies_dict)  # Second call

        assert prepared_request.headers["Cookie"] == 'session_id=abc123'

    def test_prepare_cookies_removes_cookie_header(self, prepared_request, monkeypatch):
        cookies_dict = {'session_id': 'abc123'}
        monkeypatch.setattr(prepared_request, 'headers', {})

        def mock_get_cookie_header(cookies, request):
            return 'session_id=abc123'

        monkeypatch.setattr('get_cookie_header', mock_get_cookie_header)

        prepared_request.prepare_cookies(cookies_dict)
        assert "Cookie" in prepared_request.headers

        prepared_request.headers.pop("Cookie")
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == 'session_id=abc123'

    def test_prepare_cookies_invalid_cookies_type(self, prepared_request):
        with pytest.raises(TypeError):
            prepared_request.prepare_cookies(123)

    def test_prepare_cookies_empty_dict(self, prepared_request):
        cookies_dict = {}
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers.get("Cookie") is None

    def test_prepare_cookies_none(self, prepared_request):
        prepared_request.prepare_cookies(None)
        assert prepared_request.headers.get("Cookie") is None

