import pytest

class MockRequest:
    def __init__(self, method, headers=None):
        self.method = method
        self.headers = headers if headers is not None else {}

    def prepare_content_length(self, body):
        if body is not None:
            length = super_len(body)
            if length:
                self.headers["Content-Length"] = builtin_str(length)
        elif (
            self.method not in ("GET", "HEAD")
            and self.headers.get("Content-Length") is None
        ):
            self.headers["Content-Length"] = "0"

def super_len(body):
    return len(body)

def builtin_str(value):
    return str(value)

def test_prepare_content_length_with_body():
    request = MockRequest("POST")
    request.prepare_content_length("Hello, World!")
    assert request.headers["Content-Length"] == "13"

def test_prepare_content_length_with_empty_body():
    request = MockRequest("POST")
    request.prepare_content_length("")
    assert request.headers["Content-Length"] == "0"

def test_prepare_content_length_with_none_body():
    request = MockRequest("POST")
    request.prepare_content_length(None)
    assert request.headers["Content-Length"] == "0"

def test_prepare_content_length_with_get_method():
    request = MockRequest("GET")
    request.prepare_content_length(None)
    assert "Content-Length" not in request.headers

def test_prepare_content_length_with_head_method():
    request = MockRequest("HEAD")
    request.prepare_content_length(None)
    assert "Content-Length" not in request.headers

def test_prepare_content_length_no_body_for_non_get_head():
    request = MockRequest("PUT")
    request.prepare_content_length(None)
    assert request.headers["Content-Length"] == "0"

def test_prepare_content_length_with_existing_content_length():
    request = MockRequest("POST", headers={"Content-Length": "5"})
    request.prepare_content_length(None)
    assert request.headers["Content-Length"] == "5"

def test_prepare_content_length_with_large_body():
    request = MockRequest("POST")
    large_body = "A" * 1000
    request.prepare_content_length(large_body)
    assert request.headers["Content-Length"] == "1000"

