    request = MockRequest("POST")
    request.prepare_content_length(12345)
    assert request.headers["Content-Length"] == "5"

def test_prepare_content_length_with_non_ascii_body():
    request = MockRequest("POST")
    non_ascii_body = "你好"
    request.prepare_content_length(non_ascii_body)
    assert request.headers["Content-Length"] == "6"  # Assuming UTF-8 encoding

