import pytest
from unittest.mock import Mock

class HTTPError(Exception):
    pass

class Response:
    def __init__(self, status_code, reason, url):
        self.status_code = status_code
        self.reason = reason
        self.url = url

    def raise_for_status(self):
        http_error_msg = ""
        if isinstance(self.reason, bytes):
            try:
                reason = self.reason.decode("utf-8")
            except UnicodeDecodeError:
                reason = self.reason.decode("iso-8859-1")
        else:
            reason = self.reason

        if 400 <= self.status_code < 500:
            http_error_msg = (
                f"{self.status_code} Client Error: {reason} for url: {self.url}"
            )

        elif 500 <= self.status_code < 600:
            http_error_msg = (
                f"{self.status_code} Server Error: {reason} for url: {self.url}"
            )

        if http_error_msg:
            raise HTTPError(http_error_msg, response=self)

def test_raise_for_status_client_error():
    response = Response(404, "Not Found", "http://example.com")
    with pytest.raises(HTTPError, match="404 Client Error: Not Found for url: http://example.com"):
        response.raise_for_status()

def test_raise_for_status_server_error():
    response = Response(500, "Internal Server Error", "http://example.com")
    with pytest.raises(HTTPError, match="500 Server Error: Internal Server Error for url: http://example.com"):
        response.raise_for_status()

def test_raise_for_status_bytes_utf8():
    response = Response(404, b"Not Found", "http://example.com")
    with pytest.raises(HTTPError, match="404 Client Error: Not Found for url: http://example.com"):
        response.raise_for_status()

