    response = MockResponse(b'', 'utf-8')
    assert response.text() == ''

def test_text_with_none_content():
    response = MockResponse(None, 'utf-8')
    assert response.text() == ''

def test_text_with_invalid_encoding():
    response = MockResponse(b'Hello, world!', 'invalid-encoding')
    assert response.text() == 'Hello, world!'  # Should fall back to replace

def test_text_with_type_error_on_encoding():
    response = MockResponse(b'Hello, world!', None, None)
    assert response.text() == 'Hello, world!'  # Should fall back to replace

def test_text_with_lookup_error_on_encoding():
    response = MockResponse(b'Hello, world!', 'unknown-encoding')
    assert response.text() == 'Hello, world!'  # Should fall back to replace

def test_text_with_non_bytes_content():
    response = MockResponse('Hello, world!', 'utf-8')
    assert response.text() == 'Hello, world!'  # Should handle str input

def test_text_with_large_content():
    large_content = b'A' * (10**6)  # 1 MB of data
    response = MockResponse(large_content, 'utf-8')
    assert response.text() == 'A' * (10**6)

