        result = self.mock_instance._format_timeframe('days', -3)
        assert result == '3 දින'

    def test_format_timeframe_hours_future(self):
        result = self.mock_instance._format_timeframe('hours', 2)
        assert result == '2 පැය'

    def test_format_timeframe_hours_past(self):
        result = self.mock_instance._format_timeframe('hours', -1)
        assert result == '1 පැය පෙර'

    def test_format_timeframe_minutes_future(self):
        result = self.mock_instance._format_timeframe('minutes', 10)
