    def test_format_timeframe_minutes_past(self):
        result = self.mock_instance._format_timeframe('minutes', -15)
        assert result == '15 මිනිත්තු පෙර'

    def test_format_timeframe_zero_delta(self):
        result = self.mock_instance._format_timeframe('hours', 0)
        assert result == '0 පැය'

    def test_format_timeframe_large_positive_delta(self):
        result = self.mock_instance._format_timeframe('days', 1000)
        assert result == '1000 දින'

    def test_format_timeframe_large_negative_delta(self):
        result = self.mock_instance._format_timeframe('days', -500)
        assert result == '500 දින'

    def test_format_timeframe_invalid_timeframe(self):
        with pytest.raises(KeyError):
            self.mock_instance._format_timeframe('invalid', 5)

    def test_format_timeframe_invalid_delta_type(self):
        with pytest.raises(TypeError):
            self.mock_instance._format_timeframe('hours', 'five')

