import pytest

# Assuming the constants are defined as follows
MAX_TIMESTAMP = 1_000_000_000  # 1 billion
MAX_TIMESTAMP_MS = 1_000_000_000_000  # 1 trillion (milliseconds)
MAX_TIMESTAMP_US = 1_000_000_000_000_000  # 1 quadrillion (microseconds)

def normalize_timestamp(timestamp: float) -> float:
    """Normalize millisecond and microsecond timestamps into normal timestamps."""
    if timestamp > MAX_TIMESTAMP:
        if timestamp < MAX_TIMESTAMP_MS:
            timestamp /= 1000
        elif timestamp < MAX_TIMESTAMP_US:
            timestamp /= 1_000_000
        else:
            raise ValueError(f"The specified timestamp {timestamp!r} is too large.")
    return timestamp

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1_000_000_000) == 1.0  # 1 billion is 1 second
    assert normalize_timestamp(500_000_000) == 0.5  # 500 million is 0.5 seconds

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1_000_000_000_000) == 1_000.0  # 1 trillion is 1000 seconds
    assert normalize_timestamp(1_500_000_000_000) == 1_500.0  # 1.5 trillion is 1500 seconds

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1_000_000_000_000_000) == 1_000_000.0  # 1 quadrillion is 1 million seconds
    assert normalize_timestamp(1_500_000_000_000_000) == 1_500_000.0  # 1.5 quadrillion is 1.5 million seconds

def test_normalize_timestamp_edge_cases():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP  # Edge case at MAX_TIMESTAMP
    assert normalize_timestamp(MAX_TIMESTAMP_MS - 1) == (MAX_TIMESTAMP_MS - 1) / 1000  # Just below MAX_TIMESTAMP_MS
    assert normalize_timestamp(MAX_TIMESTAMP_US - 1) == (MAX_TIMESTAMP_US - 1) / 1_000_000  # Just below MAX_TIMESTAMP_US

def test_normalize_timestamp_too_large():
    with pytest.raises(ValueError, match=r"The specified timestamp 1.0e+15 is too large."):
        normalize_timestamp(MAX_TIMESTAMP_US)

def test_normalize_timestamp_negative():
    assert normalize_timestamp(-1) == -1  # Negative timestamps should remain unchanged

def test_normalize_timestamp_zero():
    assert normalize_timestamp(0) == 0  # Zero should remain zero

def test_normalize_timestamp_small_values():
    assert normalize_timestamp(0.5) == 0.5  # Small positive value
    assert normalize_timestamp(0.0001) == 0.0001  # Very small positive value

