        self.instance = YourClass()  # Replace with the actual class name
        self.instance.timeframes = {
            'day': {
                'past': 'pred {} dňami',
                'future': 'za {} dňami',
                'future-singular': 'za {} dňom',
                'future-paucal': 'za {} dňami',
                'zero': 'dnes'
            },
            'hour': {
                'past': 'pred {} hodinami',
                'future': 'za {} hodinami',
                'future-singular': 'za {} hodinou',
                'future-paucal': 'za {} hodinami',
                'zero': 'teraz'
            }
        }

    def test_format_timeframe_past(self):
        assert self.instance._format_timeframe('day', -3) == 'pred 3 dňami'
        assert self.instance._format_timeframe('hour', -1) == 'pred 1 hodinou'

    def test_format_timeframe_future(self):
        assert self.instance._format_timeframe('day', 3) == 'za 3 dňami'
        assert self.instance._format_timeframe('hour', 1) == 'za 1 hodinou'

    def test_format_timeframe_future_singular(self):
        assert self.instance._format_timeframe('day', 1) == 'za 1 dňom'
        assert self.instance._format_timeframe('hour', 1) == 'za 1 hodinou'

    def test_format_timeframe_future_paucal(self):
        assert self.instance._format_timeframe('day', 2) == 'za 2 dňami'
        assert self.instance._format_timeframe('day', 4) == 'za 4 dňami'
        assert self.instance._format_timeframe('day', 22) == 'za 22 dňami'

    def test_format_timeframe_zero(self):
        assert self.instance._format_timeframe('day', 0) == 'dnes'
        assert self.instance._format_timeframe('hour', 0) == 'teraz'

    def test_format_timeframe_edge_cases(self):
        assert self.instance._format_timeframe('day', -2) == 'pred 2 dňami'
        assert self.instance._format_timeframe('day', -4) == 'pred 4 dňami'
        assert self.instance._format_timeframe('hour', -3) == 'pred 3 hodinami'

    def test_format_timeframe_invalid_timeframe(self):
        with pytest.raises(KeyError):
            self.instance._format_timeframe('invalid', 1)

    def test_format_timeframe_invalid_delta_type(self):
        with pytest.raises(TypeError):
            self.instance._format_timeframe('day', 'invalid')

    def test_format_timeframe_large_delta(self):
        assert self.instance._format_timeframe('day', 100) == 'za 100 dňami'
        assert self.instance._format_timeframe('hour', 100) == 'za 100 hodinami'

