import pytest
from itertools import islice

def repeat_last(iterable, default=None):
    item = _marker
    for item in iterable:
        yield item
    final = default if item is _marker else item
    yield from repeat(final)

_marker = object()

def test_repeat_last_normal_cases():
    assert list(islice(repeat_last(range(3)), 5)) == [0, 1, 2, 2, 2]
    assert list(islice(repeat_last([1, 2, 3]), 5)) == [1, 2, 3, 3, 3]
    assert list(islice(repeat_last('abc'), 5)) == ['a', 'b', 'c', 'c', 'c']

def test_repeat_last_empty_iterable_with_default():
    assert list(islice(repeat_last(range(0), 42), 5)) == [42, 42, 42, 42, 42]
    assert list(islice(repeat_last([], 'default'), 5)) == ['default', 'default', 'default', 'default', 'default']

def test_repeat_last_empty_iterable_without_default():
    assert list(islice(repeat_last([], None), 5)) == [None, None, None, None, None]

def test_repeat_last_single_element():
    assert list(islice(repeat_last([5]), 5)) == [5, 5, 5, 5, 5]
    assert list(islice(repeat_last(['single']), 5)) == ['single', 'single', 'single', 'single', 'single']

def test_repeat_last_large_iterable():
    assert list(islice(repeat_last(range(1000)), 1005)) == list(range(1000)) + [999, 999, 999, 999, 999]

def test_repeat_last_with_non_iterable():
    with pytest.raises(TypeError):
        list(islice(repeat_last(123), 5))

def test_repeat_last_with_generator():
    def gen():
        yield from range(3)

    assert list(islice(repeat_last(gen()), 5)) == [0, 1, 2, 2, 2]

def test_repeat_last_with_custom_object():
    class CustomObject:
        def __init__(self, value):
            self.value = value

        def __repr__(self):
            return f'CustomObject({self.value})'

    obj = CustomObject(10)
    assert list(islice(repeat_last([obj]), 5)) == [obj, obj, obj, obj, obj]

