import pytest
from itertools import cycle, islice

def count_cycle(iterable, n=None):
    """Cycle through the items from *iterable* up to *n* times, yielding
    the number of completed cycles along with each item. If *n* is omitted the
    process repeats indefinitely.

    >>> list(count_cycle('AB', 3))
    [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    """
    if n is not None:
        return product(range(n), iterable)
    seq = tuple(iterable)
    if not seq:
        return iter(())
    counter = count() if n is None else range(n)
    return zip(repeat_each(counter, len(seq)), cycle(seq))

def repeat_each(counter, length):
    for count in counter:
        for _ in range(length):
            yield count

def test_count_cycle_normal_cases():
    assert list(count_cycle('AB', 3)) == [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    assert list(count_cycle([1, 2, 3], 2)) == [(0, 1), (0, 2), (0, 3), (1, 1), (1, 2), (1, 3)]
    assert list(count_cycle('XYZ', 1)) == [(0, 'X'), (0, 'Y'), (0, 'Z')]
    assert list(count_cycle(range(3), 0)) == []

def test_count_cycle_edge_cases():
    assert list(count_cycle('', 3)) == []
    assert list(count_cycle([], 3)) == []
    assert list(count_cycle('A', 1)) == [(0, 'A')]
    assert list(count_cycle('A', 0)) == []

def test_count_cycle_infinite_cases():
    infinite_gen = count_cycle('AB')
    assert list(islice(infinite_gen, 6)) == [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    infinite_gen = count_cycle(range(2))
    assert list(islice(infinite_gen, 4)) == [(0, 0), (0, 1), (1, 0), (1, 1)]

def test_count_cycle_error_conditions():
    with pytest.raises(TypeError):
        list(count_cycle(None))
    with pytest.raises(TypeError):
        list(count_cycle(123))
    with pytest.raises(TypeError):
        list(count_cycle(object()))

